import React from 'react'
import { useStaticQuery, graphql } from "gatsby"
import { getSrc } from "gatsby-plugin-image"
import ForceGraph2D from 'react-force-graph-2d'
import { forceX, forceY, forceCollide } from 'd3-force-3d'
import { withSize } from 'react-sizeme';
import Link from "../IntlLink"
import FA from "../FA"
import Autocomplete from '@material-ui/lab/Autocomplete';
import TextField from '@material-ui/core/TextField';

import classNames from "classnames/bind"
import styles from "./styles.module.scss"

function AuthorsGraph({ size, lang }) {

	const cx = classNames.bind(styles);

	const {publications, placeholder, members} = useStaticQuery(graphql`
		query GraphQuery {
			publications: allMdx(filter: {fields: {collection: {in: ["thaipublica", "abridged", "pierspectives", "dp"]}}}) {
				nodes {
					frontmatter {
						authors
						title
					}
					fields {
						collection
						slug
					}
				}
			}
			placeholder: allFile(
				filter: {sourceInstanceName: {eq: "images"}, relativeDirectory: {eq: "placeholder"}, name: {eq: "user"}}
			) {
				nodes {
					childImageSharp {
						gatsbyImageData(layout: CONSTRAINED, width: 80, height: 80)
					}
				}
			}
			members: allMdx(filter: {fields: {collection: {eq: "members"}}, frontmatter: {exclude: {ne: true}}}) {
				nodes {
					frontmatter {
						memberid
						title
						org
						image {
							childImageSharp {
								gatsbyImageData(layout: CONSTRAINED, width: 160, height: 160)
							}
						}
					}
					fields {
						lang
						originalPath
					}
				}
			}
		}
	`)

	const data = React.useMemo(() => {

		function genImage(src) {
			const img = new Image();
	    img.src = src;
	    return img;
		}

		const allNodes = members.nodes.filter(node => node.fields.lang === lang).map(author => ({
			id: author.frontmatter.memberid,
			image: genImage(getSrc(author.frontmatter.image ? author.frontmatter.image.childImageSharp.gatsbyImageData : placeholder.nodes[0].childImageSharp.gatsbyImageData)),
			title: author.frontmatter.title,
			slug: author.fields.originalPath,
		}))

		const nodeArray = allNodes.map(node => node.id)

		function addLinks(collection, authorsArray) {
			if (!authorsArray)
				return
			authorsArray = authorsArray.filter(author => nodeArray.includes(author))
			authorsArray.sort()
			for (let i = 0; i < authorsArray.length; i ++) {
				for (let j = i + 1; j < authorsArray.length; j ++) {
					const key = authorsArray[i] + " - " + authorsArray[j]
					if (key in collection) {
						collection[key].weight ++
					}
					else {
						collection[key] = {source: authorsArray[i], target: authorsArray[j], weight: 1}
					}
				}
			}
		}

		let allLinks = {}
		publications.nodes.forEach(item => {
			addLinks(allLinks, item.frontmatter.authors)
		})
		allLinks = Object.values(allLinks).map(link => (link))

		return {nodes: allNodes, links: allLinks}

	}, [])

	
	function nodePaint(node, ctx) {
		const size = 80
		let color = "#3b5f74"
		let strokeWidth = 2
		if (nodeClicked && node.id === nodeClicked.id) {
			color = "#d46844"
			strokeWidth = 4
		}
		ctx.fillStyle = color; //color doesn't matter, but we want full opacity
		ctx.beginPath();
		ctx.arc(node.x, node.y, 40 + strokeWidth, 0, 2 * Math.PI, true);
		ctx.closePath();
		ctx.fill();
		ctx.save()
		ctx.fillStyle = color; //color doesn't matter, but we want full opacity
		ctx.beginPath();
		ctx.arc(node.x, node.y, 40, 0, 2 * Math.PI, true);
		ctx.closePath();
		ctx.fill();
		ctx.clip()
		ctx.drawImage(node.image, node.x - size / 2, node.y - size / 2, size, size);
		ctx.restore()
	}

	const fgRef = React.useRef();
	const [nodeClicked, setNodeClicked] = React.useState(null)

	const [value, setValue] = React.useState(null);
  const [inputValue, setInputValue] = React.useState('');

	React.useEffect(() => {
		// add collision force
		fgRef.current.d3Force('centerX', forceX(0));
		fgRef.current.d3Force('centerY', forceY(0));
		fgRef.current.d3Force('link').strength(link => link.weight / 2);
		fgRef.current.d3Force('link').distance(120);
		fgRef.current.d3Force('charge').strength(-600);
		fgRef.current.d3Force('collision', forceCollide(50))
	}, []);

	React.useEffect(() => {
		fgRef.current.zoom(Math.sqrt(size.width / 12000), 1000)
		zoomFit()
	}, [size])

	React.useEffect(() => {
		setValue(nodeClicked)
	}, [nodeClicked])

	function zoomFit() {
		// setTimeout(() => {
		// 	fgRef.current.zoomToFit(5000)
		// }, 3000)
	}

	function handleNodeClick(node) {
		setNodeClicked(node)
	}

	function renderInput(params) {
    return(
      <div className="search">
        <TextField
          {...params}
          label="Search"
          color="secondary"
          inputProps={{
            ...params.inputProps,
            autoComplete: 'new-password', // disable autocomplete and autofill
          }}
        />
				{nodeClicked &&
					<Link to={nodeClicked.slug}>
						Profile <span className="inline-svg"><FA icon="link" /></span>
					</Link>
				}
        {/* <IconButton
          aria-label="locate"
          disabled={value === null}
          // onClick={focusNode}
        >
          <LocationSearchingIcon />
        </IconButton> */}
      </div>
    )
  }

	return (
		<div className={cx("graph")} onClick={undefined}>
			<ForceGraph2D
				ref={fgRef}
				graphData={data}
				nodeVal={100} // size of node
				nodeLabel="name"
				nodeCanvasObject={(node, ctx) => nodePaint(node, ctx)}
				// onNodeHover={(node) => handleHover(node)}
				onNodeClick={handleNodeClick}
				linkWidth={link => link.weight}
				enableZoomInteraction={false}
				// enablePanInteraction={false}
				onNodeDragEnd={zoomFit}
				width={size.width}
				height={600}
			/>
			<div className={cx("select")}>
				<Autocomplete
					value={value}
					onChange={(event, newValue) => {
						setValue(newValue);
						setNodeClicked(newValue)
						document.activeElement.blur()
					}}
					inputValue={inputValue}
					onInputChange={(event, newInputValue) => setInputValue(newInputValue)}
					size="small"
					style={{ width: 300 }}
					options={data.nodes}
					clearOnEscape
					autoSelect
					autoHighlight
					getOptionLabel={option => option.title}
					renderInput={renderInput}
				/>
			</div>
		</div>
	);
}

export default withSize()(AuthorsGraph)